const body = $json.body;
const items = body.items;
const subtotal = items.reduce((s, i) => s + (i.total_price_cents || i.base_price_cents * i.qty), 0);
const order_id = 'UTO-' + Date.now();

const square_body = JSON.stringify({
  idempotency_key: order_id,
  order: {
    location_id: 'J4B6A3X6RYA63',
    reference_id: order_id,
    line_items: items.map(item => ({
      name: item.name,
      quantity: String(item.qty),
      base_price_money: {
        amount: item.base_price_cents,
        currency: 'USD'
      }
    }))
  }
});

return { json: { square_body, order_id, customer: body.customer } };
